import logging
import os
import azure.functions as func
from azure.storage.blob import BlobServiceClient

app = func.FunctionApp()

@app.route(route="readblob", auth_level=func.AuthLevel.FUNCTION)
def readblob(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Python HTTP trigger function processed a request.')

    try:
        blob_path = req.params.get('path')
        if not blob_path:
            return func.HttpResponse(
                "Please pass a 'path' query parameter with the blob path.",
                status_code=400
            )

        # Retrieve connection string from environment variables
        connect_str = os.environ.get('AzureWebJobsStorage')
        if not connect_str:
            return func.HttpResponse(
                "AzureWebJobsStorage environment variable not set.",
                status_code=500
            )

        container_name = os.environ.get('BLOB_CONTAINER_NAME')
        if not container_name:
            return func.HttpResponse(
                "BLOB_CONTAINER_NAME environment variable not set.",
                status_code=500
            )

        # Create the BlobServiceClient object
        blob_service_client = BlobServiceClient.from_connection_string(connect_str)
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_path)

        # Download blob content
        blob_data = blob_client.download_blob().readall()

        # Determine content type (optional, but good for file serving)
        # You might want a more robust content type detection based on file extension
        # For simplicity, we'll use a generic one or try to infer from blob properties
        content_settings = blob_client.get_blob_properties().content_settings
        content_type = content_settings.content_type if content_settings and content_settings.content_type else 'application/octet-stream'

        return func.HttpResponse(
            blob_data,
            mimetype=content_type,
            status_code=200
        )

    except Exception as e:
        logging.error(f"An error occurred: {e}")
        return func.HttpResponse(
            f"An error occurred while trying to read the blob: {e}",
            status_code=500
        )